// Partial<T> makes every property optional -- great for updates
interface User {
  id: number;
  name: string;
  email: string;
}

function updateUser(id: number, changes: Partial<User>): void {
  console.log('Updating', id, 'with', changes);
}

updateUser(1, { name: 'Alice' }); // only send the fields that changed

// Pick<T, K> creates a type with only the selected keys
interface User {
  id: number;
  name: string;
  email: string;
  password: string;
}

// PublicProfile only has id and name -- password is excluded
type PublicProfile = Pick<User, 'id' | 'name'>;

const profile: PublicProfile = { id: 1, name: 'Alice' };

// Omit<T, K> is the inverse of Pick -- it REMOVES keys
interface User {
  id: number;
  name: string;
  email: string;
  password: string;
}

// SafeUser has everything EXCEPT password
type SafeUser = Omit<User, 'password'>;

const user: SafeUser = { id: 1, name: 'Alice', email: 'a@b.com' };

// Record<K, V> creates a type where each key K maps to a V
// Useful for lookup tables and enum-like mappings
type Page = 'home' | 'about' | 'contact';

const routes: Record<Page, string> = {
  home: '/',
  about: '/about',
  contact: '/contact'
};

// ReturnType<T> extracts what a function type returns
function createUser() {
  return { id: 1, name: 'Alice' };
}

// UserType is { id: number; name: string } -- the return shape
type UserType = ReturnType<typeof createUser>;

const user: UserType = { id: 2, name: 'Bob' };

// Awaited<T> unwraps Promise types to get the inner type
async function fetchData(): Promise<string[]> {
  return ['a', 'b', 'c'];
}

// DataType is string[] -- the Promise wrapper is stripped away
type DataType = Awaited<ReturnType<typeof fetchData>>;

type AlsoString = Awaited<Promise<string>>; // also string
